167	interface Policy {
168	  items: Item[];
169	  remainingCap: number;
170	}
171	
172	interface ScenarioState {
173	  customer: Customer;
174	  policies: Map<number, Policy>;
175	  quoteIndex: number;
176	  stepIndex: number;
177	}
178	
179	const processQuote = (step: QuoteStep, state: ScenarioState): QuoteResult => {
180	  state.policies.set(state.stepIndex, {
181	    items: step.items,
182	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
183	  });
184	  return {
185	    premium: quotePremium(step.items, state.customer, state.quoteIndex),
186	  };
187	};
188	
189	const reimbursementRate = (item: Item): number =>
190	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
191	    ? HIGH_ENCHANTMENT_CLAIM_RATE
192	    : 1;
193	
194	const damagePayout = (damage: Damage, items: Item[]): number => {
195	  const item = items.find((it) => it.type === damage.itemType) as Item;
196	  return damage.amount * reimbursementRate(item) - DEDUCTIBLE;
197	};
198	
199	const processClaim = (step: ClaimStep, state: ScenarioState): ClaimResult => {
200	  const policy = state.policies.get(step.policy) as Policy;
201	  const payout = step.incident.damages.reduce(
202	    (sum, damage) => sum + damagePayout(damage, policy.items),
203	    0,
204	  );
205	  policy.remainingCap -= payout;
206	  return { payout, remainingCap: policy.remainingCap };
207	};
208	
209	const processStep = (step: Step, state: ScenarioState): StepResult =>
210	  step.op === "quote" ? processQuote(step, state) : processClaim(step, state);
211	
212	const quoteIndexAt = (steps: Step[], stepIndex: number): number =>
213	  steps.slice(0, stepIndex).filter((s) => s.op === "quote").length;
214	
215	export const processScenario = (scenario: Scenario): ScenarioOutput => {
216	  const policies = new Map<number, Policy>();
217	  const results: StepResult[] = scenario.steps.map((step, stepIndex) =>
218	    processStep(step, {
219	      customer: scenario.customer,
220	      policies,
221	      quoteIndex: quoteIndexAt(scenario.steps, stepIndex),
222	      stepIndex,
223	    }),
224	  );
225	  return { results };
226	};
